from locust import HttpUser, task, between

class CacheUser(HttpUser):
    wait_time = between(0.1, 0.5)

    @task(3)
    def get_cache(self):
        self.client.get("/cache/key123", name="GET /cache/{key}")

    @task(1)
    def set_cache(self):
        self.client.post("/cache", json={"key": "key123", "value": "data", "ttl": 60}, name="POST /cache")

